previewCss:
.darma-loader-loaders-css-28 {
      display: inline-grid;
      grid-template-columns: repeat(2, 15px);
      gap: 8px;
    }
    .darma-loader-loaders-css-28 i {
      width: 15px;
      height: 15px;
      border-radius: 4px;
      background: var(--loader-color);
      animation: darma-loader-loaders-css-28-gridFlash 0.9s ease-in-out infinite;
    }
    .darma-loader-loaders-css-28 i:nth-child(1) { animation-delay: 0.00s; }
.darma-loader-loaders-css-28 i:nth-child(2) { animation-delay: 0.08s; }
.darma-loader-loaders-css-28 i:nth-child(3) { animation-delay: 0.08s; }
.darma-loader-loaders-css-28 i:nth-child(4) { animation-delay: 0.16s; }
    @keyframes darma-loader-loaders-css-28-gridFlash { 0%, 70%, 100% { opacity: .25; transform: scale(.75); } 35% { opacity: 1; transform: scale(1); } }

